    data: { status: 'CLAIMED', claimedAt: new Date() },
  });

  if (updated.count === 0) {
    return; // Already claimed or not completed
  }

  const userQuest = await prisma.userQuest.findUnique({
    where: { userId_questId: { userId, questId } },
    include: { quest: true },
  });

  if (!userQuest) {
    return;
  }

  const quest = userQuest.quest;

