import { Server, Socket } from 'socket.io'
import jwt from 'jsonwebtoken'
import { prisma } from '../lib/prisma'
import { cache, CacheKeys, CacheTTL } from '../lib/redis'
import { chatService } from '../modules/chat/chat.service'
import { dmService } from '../modules/dm/dm.service'
import { proactiveNotificationService } from '../modules/ai/proactive-notification.service'
import { moodService } from '../modules/character/mood.service'
import { createModuleLogger } from '../lib/logger'
import { MESSAGE_LIMITS, CACHE_TTL, RATE_LIMITS, TIMINGS } from '../lib/constants'

const log = createModuleLogger('Socket')

// Rate limiting state (per user per event type)
const rateLimiters = new Map<string, { count: number; resetAt: number }>()

function checkRateLimit(userId: string, eventType: 'message' | 'dm' | 'typing'): boolean {
  const key = `${userId}:${eventType}`
  const now = Date.now()
  const config = eventType === 'message'
    ? RATE_LIMITS.SOCKET_MESSAGE_SEND
    : eventType === 'dm'
    ? RATE_LIMITS.SOCKET_DM_SEND
    : RATE_LIMITS.SOCKET_TYPING

  const limiter = rateLimiters.get(key)

  if (!limiter || now > limiter.resetAt) {
    rateLimiters.set(key, { count: 1, resetAt: now + config.WINDOW_MS })
    return true
  }

  if (limiter.count >= config.MAX_REQUESTS) {
    return false
  }

  limiter.count++
  return true
}

interface AuthenticatedSocket extends Socket {
  userId?: string
}

interface JwtPayload {
  userId: string
  email: string
}

export function setupSocketHandlers(io: Server) {
  // Authentication middleware
  io.use(async (socket: AuthenticatedSocket, next) => {
    try {
      const token = socket.handshake.auth.token || socket.handshake.headers.authorization?.split(' ')[1]

      if (!token) {
        return next(new Error('Authentication required'))
      }

      const decoded = jwt.verify(
        token,
        process.env.JWT_SECRET!,
        { algorithms: ['HS256'] }
      ) as JwtPayload

      // Use cache-aside pattern (same as auth middleware) instead of raw DB query
      const cacheKey = CacheKeys.userAuth(decoded.userId)
      let user = await cache.get<{ id: string; email: string }>(cacheKey)
      if (!user) {
        const dbUser = await prisma.user.findUnique({
          where: { id: decoded.userId },
          select: { id: true, email: true },
        })
        if (dbUser) {
          await cache.set(cacheKey, dbUser, CacheTTL.SOCKET_AUTH)
          user = dbUser
        }
      }

      if (!user) {
        return next(new Error('User not found'))
      }

      socket.userId = user.id
      next()
    } catch {
      next(new Error('Invalid token'))
    }
  })

  io.on('connection', (socket: AuthenticatedSocket) => {
    const userId = socket.userId!
    const userRoom = `user:${userId}`

    // Join user's room for cross-tab sync
    socket.join(userRoom)

    // Check for proactive notifications (debounced per user — once per 5 minutes)
    ;(async () => {
      try {
        const notifDebounceKey = `proactive_notif:${userId}`
        const recentlyChecked = await cache.get<boolean>(notifDebounceKey)
        if (recentlyChecked) return

        // Cache character list for 5 minutes to avoid repeated DB queries
        const charCacheKey = `user:${userId}:characters:list`
        let characters = await cache.get<Array<{ id: string; name: string }>>(charCacheKey)

        if (!characters) {
          characters = await prisma.character.findMany({
            where: { userId },
            select: { id: true, name: true },
          })
          await cache.set(charCacheKey, characters, 300) // 5 minutes
        }

        for (const character of characters) {
          const result = await proactiveNotificationService.checkAndSendNotification(character.id)
          if (result.shouldSend && result.notification) {
            // Broadcast to all user's tabs
            io.to(userRoom).emit('notification:proactive', {
              characterId: character.id,
              characterName: character.name,
              type: result.notification.type,
              message: result.notification.message,
              sourceSocketId: socket.id,
            })
          }
        }

        // Set debounce flag for 5 minutes
        await cache.set(notifDebounceKey, true, 300)
      } catch (err) {
        log.error('Proactive notification error:', err)
      }
    })()

    // Handle mood check request
    socket.on('character:mood_check', async (data: { characterId: string }) => {
      try {
        const mood = await moodService.getCurrentMood(data.characterId)
        // Broadcast mood update to all user's tabs
        io.to(userRoom).emit('character:mood_update', {
          characterId: data.characterId,
          ...mood,
          sourceSocketId: socket.id,
        })
      } catch (err) {
        log.error('Mood check error:', err)
      }
    })

    // Handle sending messages
    socket.on('message:send', async (data: {
      characterId: string
      content: string
      messageType?: string
      clientId?: string
    }) => {
      try {
        // Rate limiting
        if (!checkRateLimit(userId, 'message')) {
          socket.emit('error', { message: 'Too many messages. Please slow down.' })
          return
        }

        // Input validation
        if (!data.content || typeof data.content !== 'string') {
          socket.emit('error', { message: 'Message content is required' })
          return
        }

        // Sanitize and validate content length
        const content = data.content.trim()
        if (content.length === 0) {
          socket.emit('error', { message: 'Message cannot be empty' })
          return
        }
        if (content.length > MESSAGE_LIMITS.MAX_CHAT_MESSAGE_LENGTH) {
          socket.emit('error', { message: `Message too long (max ${MESSAGE_LIMITS.MAX_CHAT_MESSAGE_LENGTH} characters)` })
          return
        }

        // Atomic idempotency check — prevent duplicate processing
        if (data.clientId) {
          const dedupKey = `dedup:${userId}:${data.clientId}`
          const isNew = await cache.setNX(dedupKey, true, CACHE_TTL.DEDUPLICATION)
          if (!isNew) {
            log.debug('Duplicate message blocked:', data.clientId)
            return
          }
        }

        // Broadcast typing indicator to ALL user's tabs
        io.to(userRoom).emit('character:typing', {
          characterId: data.characterId,
          sourceSocketId: socket.id,
        })

        // Process message with validated content
        const result = await chatService.sendMessage(userId, {
          characterId: data.characterId,
          content: content,
          messageType: (data.messageType as 'TEXT') || 'TEXT',
        })

        // Broadcast user message to ALL user's tabs (echo clientId so client can replace optimistic)
        io.to(userRoom).emit('message:receive', {
          ...result.userMessage,
          isOwn: true,
          clientId: data.clientId,
          sourceSocketId: socket.id,
        })

        // Typing delay proportional to response length (min 1.5s, max 4s)
        const responseLength = result.aiMessage.content?.length || 50;
        const typingDelay = Math.min(4000, Math.max(1500, responseLength * 25));
        setTimeout(() => {
          // Broadcast AI response to ALL user's tabs
          io.to(userRoom).emit('message:receive', {
            ...result.aiMessage,
            isOwn: false,
            emotion: result.emotion,
            sourceSocketId: socket.id,
          })

          // Broadcast mood change to all tabs
          if (result.moodChange) {
            io.to(userRoom).emit('character:mood_change', {
              characterId: data.characterId,
              mood: result.moodChange,
              sourceSocketId: socket.id,
            })
          }

          // Broadcast affection update to all tabs
          if (result.affectionChange !== undefined) {
            io.to(userRoom).emit('character:affection_change', {
              characterId: data.characterId,
              change: result.affectionChange,
              newAffection: result.newAffection,
              newLevel: result.newLevel,
              levelUp: result.levelUp,
              relationshipUpgrade: result.relationshipUpgrade,
              previousStage: result.previousStage,
              newStage: result.newStage,
              unlocks: result.unlocks,
              rewards: result.rewards,
              sourceSocketId: socket.id,
            })
          }

          // Broadcast quest completion to all tabs
          if (result.questsCompleted && result.questsCompleted.length > 0) {
            result.questsCompleted.forEach(quest => {
              io.to(userRoom).emit('quest:completed', {
                ...quest,
                sourceSocketId: socket.id,
              })
            })
          }

          // Broadcast milestone unlocks to all tabs
          if (result.milestonesUnlocked && result.milestonesUnlocked.length > 0) {
            result.milestonesUnlocked.forEach(milestone => {
              io.to(userRoom).emit('milestone:unlocked', {
                milestone,
                sourceSocketId: socket.id,
              })
            })
          }
        }, 1000 + Math.random() * 2000) // 1-3 seconds delay

      } catch (error) {
        log.error('Error sending message:', error)
        socket.emit('error', { message: 'Failed to send message' })
      }
    })

    // Typing indicators - broadcast to other tabs
    socket.on('typing:start', (characterId: string) => {
      socket.to(userRoom).emit('user:typing', {
        characterId,
        sourceSocketId: socket.id
      })
    })

    socket.on('typing:stop', (characterId: string) => {
      socket.to(userRoom).emit('user:typing:stop', {
        characterId,
        sourceSocketId: socket.id
      })
    })

    // Handle tab sync request - new tab requests current state
    socket.on('sync:request', () => {
      // Broadcast to other tabs to share their state
      socket.to(userRoom).emit('sync:state_request', {
        requestingSocketId: socket.id,
      })
    })

    // Handle sync response - send state to requesting tab
    socket.on('sync:response', (data: {
      targetSocketId: string
      messages: unknown[]
      typing: boolean
    }) => {
      io.to(data.targetSocketId).emit('sync:state_receive', {
        messages: data.messages,
        typing: data.typing,
        sourceSocketId: socket.id,
      })
    })

    // ── Direct Message socket handlers ──
    socket.on('dm:send', async (data: {
      conversationId: string
      content: string
      clientId?: string
    }) => {
      try {
        // Rate limiting
        if (!checkRateLimit(userId, 'dm')) {
          socket.emit('error', { message: 'Too many messages. Please slow down.' })
          return
        }

        if (!data.content?.trim() || !data.conversationId) {
          socket.emit('error', { message: 'conversationId and content required' })
          return
        }

        // Validate content length
        if (data.content.trim().length > MESSAGE_LIMITS.MAX_DM_MESSAGE_LENGTH) {
          socket.emit('error', { message: `Message too long (max ${MESSAGE_LIMITS.MAX_DM_MESSAGE_LENGTH} characters)` })
          return
        }

        // Atomic idempotency
        if (data.clientId) {
          const dedupKey = `dedup_dm:${userId}:${data.clientId}`
          const isNew = await cache.setNX(dedupKey, true, CACHE_TTL.DEDUPLICATION)
          if (!isNew) {
            log.debug('Duplicate DM blocked:', data.clientId)
            return
          }
        }

        const message = await dmService.sendMessage(userId, data.conversationId, data.content)

        // Get conversation members to broadcast (cached for 5 minutes)
        const membersCacheKey = `conversation:${data.conversationId}:members`
        let members = await cache.get<Array<{ userId: string }>>(membersCacheKey)

        if (!members) {
          members = await prisma.conversationMember.findMany({
            where: { conversationId: data.conversationId, isActive: true },
            select: { userId: true },
          })
          await cache.set(membersCacheKey, members, 300) // 5 minutes
        }

        // Broadcast to all members' rooms
        members.forEach(member => {
          io.to(`user:${member.userId}`).emit('dm:receive', {
            ...message,
            conversationId: data.conversationId,
          })
        })
      } catch (error) {
        log.error('DM send error:', error)
        socket.emit('error', { message: 'Failed to send message' })
      }
    })

    socket.on('dm:typing', async (data: { conversationId: string }) => {
      try {
        // Rate limiting
        if (!checkRateLimit(userId, 'typing')) {
          return
        }

        // Input validation
        if (!data.conversationId) {
          return
        }

        // Broadcast typing to other members (cached to avoid DB query on every keystroke)
        const membersCacheKey = `conversation:${data.conversationId}:members`
        let members = await cache.get<Array<{ userId: string }>>(membersCacheKey)

        if (!members) {
          members = await prisma.conversationMember.findMany({
            where: { conversationId: data.conversationId, isActive: true },
            select: { userId: true },
          })
          await cache.set(membersCacheKey, members, 300) // 5 minutes
        }

        // Filter out current user and broadcast to others
        members.filter(m => m.userId !== userId).forEach(member => {
          io.to(`user:${member.userId}`).emit('dm:typing', {
            conversationId: data.conversationId,
            userId,
          })
        })
      } catch (error) {
        log.error('DM typing error:', error)
      }
    })

    socket.on('dm:read', async (data: { conversationId: string }) => {
      try {
        await dmService.markRead(userId, data.conversationId)
      } catch {}
    })

    // Handle disconnection
    socket.on('disconnect', () => {
      // User disconnected from this tab
    })
  })

  // Helper function to send notifications (used by other modules)
  const sendNotification = (userId: string, notification: {
    type: string
    title: string
    message: string
    data?: Record<string, unknown>
  }) => {
    io.to(`user:${userId}`).emit('notification:new', notification)
  }

  return { sendNotification }
}

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001';

type RequestMethod = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';

interface RequestOptions {
  method?: RequestMethod;
  body?: unknown;
  headers?: Record<string, string>;
}

// Common API response type
interface ApiResponse<T = unknown> {
  success: boolean;
  data: T;
  message?: string;
  error?: {
    message: string;
    code?: string;
  };
}

class ApiClient {
  private baseUrl: string;
  private refreshPromise: Promise<boolean> | null = null;
  private tokenSyncChannel: BroadcastChannel | null = null;

  constructor(baseUrl: string) {
    this.baseUrl = baseUrl;
    this.initTokenSync();
  }

  // Listen for token updates from other tabs
  private initTokenSync() {
    if (typeof window === 'undefined') return;
    try {
      this.tokenSyncChannel = new BroadcastChannel('vgfriend-token-sync');
      this.tokenSyncChannel.onmessage = (event) => {
        if (event.data?.type === 'token-updated' && event.data?.accessToken) {
          // Update localStorage with new token from another tab
          const stored = localStorage.getItem('vgfriend-auth');
          if (stored) {
            const parsed = JSON.parse(stored);
            parsed.state.accessToken = event.data.accessToken;
            if (event.data.user) parsed.state.user = event.data.user;
            localStorage.setItem('vgfriend-auth', JSON.stringify(parsed));
          }
        }
      };
    } catch {
      // BroadcastChannel not supported
    }
  }

  private broadcastTokenUpdate(accessToken: string, user?: unknown) {
    try {
      this.tokenSyncChannel?.postMessage({
        type: 'token-updated',
        accessToken,
        user,
      });
    } catch {
      // Ignore broadcast errors
    }
  }

  private getAccessToken(): string | null {
    if (typeof window === 'undefined') return null;

    try {
      const stored = localStorage.getItem('vgfriend-auth');
      if (stored) {
        const parsed = JSON.parse(stored);
        return parsed.state?.accessToken || null;
      }
    } catch {
      return null;
    }
    return null;
  }

  private async request<T>(endpoint: string, options: RequestOptions = {}): Promise<ApiResponse<T>> {
    const { method = 'GET', body, headers = {} } = options;

    const token = this.getAccessToken();

    const config: RequestInit = {
      method,
      headers: {
        'Content-Type': 'application/json',
        ...(token && { Authorization: `Bearer ${token}` }),
        ...headers,
      },
      credentials: 'include',
    };

    if (body) {
      config.body = JSON.stringify(body);
    }

    const response = await fetch(`${this.baseUrl}${endpoint}`, config);

    // Handle 429 — rate limited, wait and retry once
    if (response.status === 429 && !options.headers?.['X-Rate-Retry']) {
      const retryAfter = response.headers.get('Retry-After');
      const waitMs = retryAfter ? parseInt(retryAfter) * 1000 : 2000;
      await new Promise(resolve => setTimeout(resolve, Math.min(waitMs, 5000)));
      return this.request<T>(endpoint, {
        ...options,
        headers: { ...headers, 'X-Rate-Retry': '1' },
      });
    }

    // Handle 401 — try refreshing the token once
    if (response.status === 401 && token && !options.headers?.['X-Retry']) {
      const refreshed = await this.tryRefreshToken();
      if (refreshed) {
        return this.request<T>(endpoint, {
          ...options,
          headers: { ...headers, 'X-Retry': '1' },
        });
      }
    }

    // Safely parse JSON (server might return HTML on 502/503)
    let data: ApiResponse<T>;
    try {
      data = await response.json();
    } catch {
      throw new Error(`Server error (${response.status})`);
    }

    // Check if response is not ok, throw with backend message
    if (!response.ok) {
      throw new Error(data.error?.message || data.message || 'Request failed');
    }

    // Also check success field in response body (for 200 responses with success: false)
    if ('success' in data && !data.success) {
      throw new Error(data.message || 'Request failed');
    }

    return data;
  }

  private async tryRefreshToken(): Promise<boolean> {
    // If a refresh is already in progress, wait for it
    if (this.refreshPromise) {
      return this.refreshPromise;
    }

    // Start the refresh and save the promise
    this.refreshPromise = this.doRefreshToken();

    try {
      return await this.refreshPromise;
    } finally {
      // Clear the promise after completion (allow future refreshes)
      this.refreshPromise = null;
    }
  }

  private async doRefreshToken(): Promise<boolean> {
    try {
      const res = await fetch(`${this.baseUrl}/auth/refresh`, {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
      });
      if (!res.ok) return false;
      const data = await res.json();
      if (data.success && data.data?.tokens?.accessToken) {
        const newToken = data.data.tokens.accessToken;
        const newUser = data.data.user;

        // Update Zustand persisted store in localStorage
        const stored = localStorage.getItem('vgfriend-auth');
        if (stored) {
          const parsed = JSON.parse(stored);
          parsed.state.accessToken = newToken;
          if (newUser) parsed.state.user = newUser;
          localStorage.setItem('vgfriend-auth', JSON.stringify(parsed));
        }

        // Broadcast to other tabs so they get the new token immediately
        this.broadcastTokenUpdate(newToken, newUser);

        return true;
      }
    } catch {
      // Refresh failed
    }
    return false;
  }

  get<T = unknown>(endpoint: string) {
    return this.request<T>(endpoint, { method: 'GET' });
  }

  post<T = unknown>(endpoint: string, body?: unknown) {
    return this.request<T>(endpoint, { method: 'POST', body });
  }

  put<T = unknown>(endpoint: string, body?: unknown) {
    return this.request<T>(endpoint, { method: 'PUT', body });
  }

  patch<T = unknown>(endpoint: string, body?: unknown) {
    return this.request<T>(endpoint, { method: 'PATCH', body });
  }

  delete<T = unknown>(endpoint: string) {
    return this.request<T>(endpoint, { method: 'DELETE' });
  }
}

export const api = new ApiClient(`${API_URL}/api`);
export default api;

import { Page, Locator, expect } from '@playwright/test';
import { BasePage } from './BasePage';

/**
 * ChatPage - Page Object for the Chat page
 * Path: /chat
 */
export class ChatPage extends BasePage {
  readonly url = '/chat';

  // Chat header
  readonly characterName: Locator;
  readonly characterMood: Locator;
  readonly backButton: Locator;
  readonly sceneButton: Locator;
  readonly giftButton: Locator;

  // Message area
  readonly messagesContainer: Locator;
  readonly messagesList: Locator;
  readonly userMessage: Locator;
  readonly botMessage: Locator;
  readonly typingIndicator: Locator;

  // Input area
  readonly messageInput: Locator;
  readonly sendButton: Locator;
  readonly emojiButton: Locator;
  readonly micButton: Locator;

  // Gift modal
  readonly giftModal: Locator;
  readonly giftItems: Locator;
  readonly sendGiftButton: Locator;
  readonly closeGiftModal: Locator;

  // Scene selector
  readonly sceneModal: Locator;
  readonly sceneItems: Locator;

  constructor(page: Page) {
    super(page);

    // Header
    this.characterName = page.locator('[data-testid="chat-character-name"], .character-name');
    this.characterMood = page.locator('[data-testid="chat-character-mood"]');
    this.backButton = page.locator('button:has(svg.lucide-arrow-left)');
    this.sceneButton = page.locator('button:has(svg.lucide-image)');
    this.giftButton = page.locator('button:has(svg.lucide-gift)');

    // Messages
    this.messagesContainer = page.locator('[data-testid="messages-container"], .messages-container');
    this.messagesList = page.locator('[data-testid="message"]');
    this.userMessage = page.locator('[data-testid="user-message"], .message-user');
    this.botMessage = page.locator('[data-testid="bot-message"], .message-bot');
    this.typingIndicator = page.locator('[data-testid="typing-indicator"], .typing-indicator');

    // Input
    this.messageInput = page.locator('input[placeholder*="Nhắn tin"], input[placeholder*="message" i], input[type="text"]:near(button:has(svg))').first();
    this.sendButton = page.locator('button:has(svg.lucide-send), button svg.lucide-send').locator('..').first();
    this.emojiButton = page.locator('button:has(svg.lucide-smile)');
    this.micButton = page.locator('button:has(svg.lucide-mic)');

    // Gift modal
    this.giftModal = page.locator('[data-testid="gift-modal"], [role="dialog"]');
    this.giftItems = page.locator('[data-testid="gift-item"]');
    this.sendGiftButton = page.locator('button:has-text("Tặng"), button:has-text("Send Gift")');
    this.closeGiftModal = page.locator('[data-testid="close-gift-modal"], button:has(svg.lucide-x)');

    // Scene selector
    this.sceneModal = page.locator('[data-testid="scene-modal"]');
    this.sceneItems = page.locator('[data-testid="scene-item"]');
  }

  async goto(): Promise<void> {
    await this.page.goto(this.url);
    await this.waitForPageLoad();
  }

  async waitForPageLoad(): Promise<void> {
    await this.messageInput.waitFor({ state: 'visible', timeout: 15000 });
    await this.waitForLoadingComplete();
  }

  /**
   * Type a message
   */
  async typeMessage(message: string): Promise<void> {
    await this.fillInput(this.messageInput, message);
  }

  /**
   * Send a message
   */
  async sendMessage(message: string): Promise<void> {
    await this.typeMessage(message);
    await this.sendButton.click();
  }

  /**
   * Send message and wait for response
   */
  async sendMessageAndWaitForResponse(message: string): Promise<void> {
    const currentMessagesCount = await this.messagesList.count();

    await this.sendMessage(message);

    // Wait for user message to appear
    await expect(this.messagesList).toHaveCount(currentMessagesCount + 1, { timeout: 5000 });

    // Wait for typing indicator
    await this.typingIndicator.waitFor({ state: 'visible', timeout: 5000 }).catch(() => {});

    // Wait for bot response
    await this.typingIndicator.waitFor({ state: 'hidden', timeout: 60000 }).catch(() => {});

    // Verify response arrived
    await expect(this.messagesList).toHaveCount(currentMessagesCount + 2, { timeout: 60000 });
  }

  /**
   * Get all messages
   */
  async getMessages(): Promise<string[]> {
    const messages: string[] = [];
    const count = await this.messagesList.count();
    for (let i = 0; i < count; i++) {
      const text = await this.messagesList.nth(i).textContent();
      if (text) messages.push(text);
    }
    return messages;
  }

  /**
   * Get last message
   */
  async getLastMessage(): Promise<string> {
    return (await this.messagesList.last().textContent()) ?? '';
  }

  /**
   * Get message count
   */
  async getMessageCount(): Promise<number> {
    return this.messagesList.count();
  }

  /**
   * Check if typing indicator is visible
   */
  async isTyping(): Promise<boolean> {
    return this.typingIndicator.isVisible();
  }

  /**
   * Open gift modal
   */
  async openGiftModal(): Promise<void> {
    await this.giftButton.click();
    await this.giftModal.waitFor({ state: 'visible' });
  }

  /**
   * Close gift modal
   */
  async closeGiftModalDialog(): Promise<void> {
    await this.closeGiftModal.click();
    await this.giftModal.waitFor({ state: 'hidden' });
  }

  /**
   * Send enter key in input
   */
  async pressEnterToSend(): Promise<void> {
    await this.messageInput.press('Enter');
  }

  /**
   * Open scene selector
   */
  async openSceneSelector(): Promise<void> {
    await this.sceneButton.click();
  }

  async verifyPageElements(): Promise<void> {
    await expect(this.messageInput).toBeVisible();
    await expect(this.sendButton).toBeVisible();
  }

  /**
   * Alias for typeMessage
   */
  async enterMessage(message: string): Promise<void> {
    await this.typeMessage(message);
  }

  /**
   * Alias for sendButton click
   */
  async clickSend(): Promise<void> {
    await this.sendButton.click();
  }

  /**
   * Check if gift modal is visible
   */
  async isGiftModalVisible(): Promise<boolean> {
    return this.giftModal.isVisible();
  }

  /**
   * Open search (if available)
   */
  async openSearch(): Promise<void> {
    const searchButton = this.page.locator('button:has(svg.lucide-search)');
    if (await searchButton.isVisible()) {
      await searchButton.click();
    }
  }

  /**
   * Check if search is visible
   */
  async isSearchVisible(): Promise<boolean> {
    const searchInput = this.page.locator('input[placeholder*="Tìm kiếm"], input[placeholder*="Search"]');
    return searchInput.isVisible();
  }

  /**
   * Search in chat
   */
  async search(query: string): Promise<void> {
    const searchInput = this.page.locator('input[placeholder*="Tìm kiếm"], input[placeholder*="Search"]');
    await searchInput.fill(query);
  }
}

