async function handleCheckoutCompleted(session: Stripe.Checkout.Session) {
  const userId = session.metadata?.userId
  if (!userId || session.mode !== 'subscription') return

  const tier = (session.metadata?.tier || 'BASIC') as PremiumTier
  const billingCycle = (session.metadata?.billingCycle || 'MONTHLY') as 'MONTHLY' | 'YEARLY'
  const stripeSubscriptionId = session.subscription as string

  if (!stripeSubscriptionId) return

  const stripe = getStripeOrThrow()
  const stripeSub = await stripe.subscriptions.retrieve(stripeSubscriptionId)
  const priceId = stripeSub.items.data[0]?.price?.id || ''
  const period = getSubPeriod(stripeSub)

  // Idempotency check: skip user activation if subscription is already ACTIVE
  // Stripe retries webhooks for up to 3 days; without this check the user
  // update runs on every retry attempt unnecessarily.
  const existingSub = await prisma.subscription.findUnique({
    where: { userId },
    select: { status: true },
  })

  if (existingSub?.status === 'ACTIVE') {
    log.debug(`User ${userId} subscription already ACTIVE, skipping duplicate webhook processing`)
    return
  }

  // Upsert subscription record
  await prisma.subscription.upsert({
    where: { userId },
    create: {
      userId,
      stripeSubscriptionId,
      stripePriceId: priceId,
      tier,
      billingCycle,
      status: 'ACTIVE',
      currentPeriodStart: period.start,
      currentPeriodEnd: period.end,
    },
    update: {
      stripeSubscriptionId,
      stripePriceId: priceId,
      tier,
      billingCycle,
      status: 'ACTIVE',
      currentPeriodStart: period.start,
      currentPeriodEnd: period.end,
      cancelAtPeriodEnd: false,
    },
  })

  // Activate premium on User
  await prisma.user.update({
    where: { id: userId },
    data: {
      isPremium: true,
      premiumTier: tier,
      premiumExpiresAt: period.end,
    },
  })

  // Invalidate auth cache
  await cache.del(`auth:user:${userId}`)

  log.info(`User ${userId} activated ${tier} ${billingCycle} subscription`)
}

