import { prisma } from '../../lib/prisma'
import { cache, CacheKeys } from '../../lib/redis'
import { AppError } from '../../middlewares/error.middleware'
import { RelationshipStage, RelationshipEventType } from '@prisma/client'
import { createModuleLogger } from '../../lib/logger'
import { RELATIONSHIP_THRESHOLDS, SCENE_PROGRESSION } from '../../lib/constants'

const log = createModuleLogger('Relationship')

// Calculate relationship stage from affection
function calculateRelationshipStage(affection: number): RelationshipStage {
  if (affection >= 900) return 'LOVER'
  if (affection >= 750) return 'DATING'
  if (affection >= 600) return 'CRUSH'
  if (affection >= 450) return 'CLOSE_FRIEND'
  if (affection >= 250) return 'FRIEND'
  if (affection >= 100) return 'ACQUAINTANCE'
  return 'STRANGER'
}

// Get progress to next stage
function getProgressToNextStage(affection: number, currentStage: RelationshipStage) {
  const stages = Object.entries(RELATIONSHIP_THRESHOLDS)
  const currentIdx = stages.findIndex(([stage]) => stage === currentStage)

  if (currentIdx === stages.length - 1) {
    return { progress: 100, nextStage: null, nextThreshold: null }
  }

  const [nextStage, nextThreshold] = stages[currentIdx + 1]
  const currentThreshold = RELATIONSHIP_THRESHOLDS[currentStage]
  const progress = Math.round(((affection - currentThreshold) / (nextThreshold - currentThreshold)) * 100)

  return { progress: Math.min(progress, 100), nextStage, nextThreshold }
}

export const relationshipService = {
  /**
   * Get relationship status and progress
   */
  async getRelationshipStatus(userId: string) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true, isEnded: false },
      include: {
        relationshipHistory: {
          orderBy: { createdAt: 'desc' },
          take: 10,
        },
      },
    })

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER')
    }

    const currentStage = character.relationshipStage
    const { progress, nextStage, nextThreshold } = getProgressToNextStage(character.affection, currentStage)

    // Get available scenes for current stage
    const currentStageIdx = Object.keys(RELATIONSHIP_THRESHOLDS).indexOf(currentStage)
    const availableSceneCategories = Object.entries(SCENE_PROGRESSION)
      .filter(([_, __], idx) => idx <= currentStageIdx)
      .flatMap(([_, categories]) => categories)

    return {
      characterId: character.id,
      characterName: character.name,
      currentStage,
      affection: character.affection,
      level: character.level,
      experience: character.experience,
      relationshipStartedAt: character.relationshipStartedAt,
      firstMetAt: character.firstMetAt,
      daysKnown: Math.floor((Date.now() - character.firstMetAt.getTime()) / (1000 * 60 * 60 * 24)),
      progressToNextStage: progress,
      nextStage,
      nextThreshold,
      recentHistory: character.relationshipHistory,
      availableSceneCategories,
    }
  },

  /**
   * Record a relationship event (stage change, milestone, etc.)
   */
  async recordEvent(
    userId: string,
    characterId: string,
    eventType: RelationshipEventType,
    data?: {
      fromStage?: RelationshipStage
      toStage?: RelationshipStage
      note?: string
      metadata?: any
    }
  ) {
    const event = await prisma.relationshipHistory.create({
      data: {
        userId,
        characterId,
        eventType,
        fromStage: data?.fromStage,
        toStage: data?.toStage,
        note: data?.note,
        metadata: data?.metadata,
      },
    })

    log.info('Relationship event recorded', { userId, characterId, eventType })
    return event
  },

  /**
   * Update affection and check for stage progression
   */
  async updateAffection(userId: string, amount: number, reason: string) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true, isEnded: false },
    })

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER')
    }

    const oldStage = character.relationshipStage
    const newAffection = Math.min(1000, Math.max(0, character.affection + amount))
    const newStage = calculateRelationshipStage(newAffection)

    const updateData: any = { affection: newAffection, relationshipStage: newStage }

    // If transitioning to DATING, record relationship start
    if (oldStage !== 'DATING' && oldStage !== 'LOVER' && (newStage === 'DATING' || newStage === 'LOVER')) {
      updateData.relationshipStartedAt = new Date()
    }

    const updated = await prisma.character.update({
      where: { id: character.id },
      data: updateData,
    })

    // Record stage progression event
    if (oldStage !== newStage) {
      await this.recordEvent(userId, character.id, 'STAGE_UP', {
        fromStage: oldStage,
        toStage: newStage,
        note: reason,
      })

      // Special events for certain stages
      if (newStage === 'DATING') {
        await this.recordEvent(userId, character.id, 'STARTED_DATING', {
          fromStage: oldStage,
          toStage: newStage,
          note: 'Chính thức bắt đầu hẹn hò!',
        })
      }
    }

    // Invalidate cache
    await cache.del(CacheKeys.character(userId))

    return {
      character: updated,
      stageChanged: oldStage !== newStage,
      oldStage,
      newStage,
      affectionChange: amount,
    }
  },

  /**
   * End relationship with current character (breakup)
   */
  async endRelationship(userId: string, reason?: string) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true, isEnded: false },
    })

    if (!character) {
      throw new AppError('No active relationship found', 404, 'NO_CHARACTER')
    }

    // Record breakup event
    await this.recordEvent(userId, character.id, 'BREAKUP', {
      fromStage: character.relationshipStage,
      note: reason || 'Kết thúc mối quan hệ',
      metadata: { affectionAtBreakup: character.affection, levelAtBreakup: character.level },
    })

    // Mark character as ended
    const updated = await prisma.character.update({
      where: { id: character.id },
      data: {
        isActive: false,
        isEnded: true,
        endedAt: new Date(),
        endReason: reason || 'user_choice',
      },
    })

    // Invalidate caches
    await cache.del(CacheKeys.character(userId))

    log.info('Relationship ended', { userId, characterId: character.id, reason })

    return {
      message: 'Mối quan hệ đã kết thúc',
      character: updated,
    }
  },

  /**
   * Get history of all relationships (current and past)
   */
  async getRelationshipHistory(userId: string) {
    const characters = await prisma.character.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      include: {
        template: true,
        _count: {
          select: { messages: true, receivedGifts: true, memories: true },
        },
      },
    })

    return characters.map(char => ({
      id: char.id,
      name: char.name,
      avatarUrl: char.avatarUrl || char.template?.avatarUrl,
      gender: char.gender,
      personality: char.personality,
      relationshipStage: char.relationshipStage,
      affection: char.affection,
      level: char.level,
      isActive: char.isActive,
      isEnded: char.isEnded,
      firstMetAt: char.firstMetAt,
      relationshipStartedAt: char.relationshipStartedAt,
      endedAt: char.endedAt,
      endReason: char.endReason,
      stats: char._count,
    }))
  },

  /**
   * Check if user can start a new relationship
   */
  async canStartNewRelationship(userId: string, premiumTier: string) {
    const characters = await prisma.character.findMany({
      where: { userId, isEnded: false },
    })

    const maxCharacters = {
      FREE: 1,
      BASIC: 2,
      PRO: 5,
      ULTIMATE: -1, // Unlimited
    }[premiumTier] ?? 1

    if (maxCharacters === -1) {
      return { canStart: true, currentCount: characters.length, maxAllowed: -1 }
    }

    return {
      canStart: characters.length < maxCharacters,
      currentCount: characters.length,
      maxAllowed: maxCharacters,
    }
  },

  /**
   * Try to reconcile with an ended relationship
   */
  async reconcileRelationship(userId: string, characterId: string) {
    const character = await prisma.character.findFirst({
      where: { id: characterId, userId, isEnded: true },
    })

    if (!character) {
      throw new AppError('Character not found or not ended', 404, 'CHARACTER_NOT_FOUND')
    }

    // Check if user has premium or enough gems for reconciliation
    const user = await prisma.user.findUnique({ where: { id: userId } })
    if (!user) {
      throw new AppError('User not found', 404, 'USER_NOT_FOUND')
    }

    const reconcileCost = 100 // Gems required to reconcile
    if (user.premiumTier === 'FREE' && user.gems < reconcileCost) {
      throw new AppError(
        `Cần ${reconcileCost} gems để quay lại với ${character.name}`,
        400,
        'INSUFFICIENT_GEMS'
      )
    }

    // Deactivate any current active relationships
    await prisma.character.updateMany({
      where: { userId, isActive: true },
      data: { isActive: false },
    })

    // Reactivate the character with reduced affection
    const newAffection = Math.floor(character.affection * 0.5) // 50% affection penalty
    const newStage = calculateRelationshipStage(newAffection)

    const updated = await prisma.character.update({
      where: { id: character.id },
      data: {
        isActive: true,
        isEnded: false,
        endedAt: null,
        endReason: null,
        affection: newAffection,
        relationshipStage: newStage,
      },
    })

    // Deduct gems for non-premium users
    if (user.premiumTier === 'FREE') {
      await prisma.user.update({
        where: { id: userId },
        data: { gems: { decrement: reconcileCost } },
      })
    }

    // Record reconciliation event
    await this.recordEvent(userId, character.id, 'RECONCILIATION', {
      toStage: newStage,
      note: 'Quay lại với nhau',
      metadata: { previousAffection: character.affection, newAffection },
    })

    // Invalidate cache
    await cache.del(CacheKeys.character(userId))

    return {
      message: `Đã quay lại với ${character.name}`,
      character: updated,
      affectionPenalty: character.affection - newAffection,
    }
  },
}

import { prisma } from '../../lib/prisma';
import { cache, CacheKeys, CacheTTL } from '../../lib/redis';
import { AppError } from '../../middlewares/error.middleware';
import { RelationshipStage, Gender } from '@prisma/client';
import { createModuleLogger } from '../../lib/logger';
import { VALIDATION } from '../../lib/constants';

const log = createModuleLogger('Character');

interface CreateCharacterData {
  name: string;
  nickname?: string;
  gender?: Gender;
  personality?: string;
  birthday?: string;
  bio?: string;
  age?: number;
  occupation?: string;
  templateId?: string;
  avatarUrl?: string;
}

interface UpdateCharacterData {
  name?: string;
  nickname?: string;
  personality?: string;
  bio?: string;
  responseStyle?: string;
  creativityLevel?: number;
  avatarUrl?: string;
  templateId?: string;
}

interface CustomizeCharacterData {
  avatarStyle?: string;
  hairStyle?: string;
  hairColor?: string;
  eyeColor?: string;
  skinTone?: string;
  outfit?: string;
  accessories?: string[];
}

interface AddFactData {
  category: string;
  key: string;
  value: string;
  importance?: number;
}

// Affection thresholds for relationship stages
const RELATIONSHIP_THRESHOLDS: Record<RelationshipStage, number> = {
  STRANGER: 0,
  ACQUAINTANCE: 100,
  FRIEND: 250,
  CLOSE_FRIEND: 450,
  CRUSH: 600,
  DATING: 750,
  IN_LOVE: 850,
  LOVER: 900,
};

// NEW: Level milestone rewards
interface LevelMilestoneReward {
  level: number;
  coins: number;
  gems: number;
  affection: number;
  unlocks: string[];
}

const LEVEL_MILESTONES: LevelMilestoneReward[] = [
  { level: 5, coins: 200, gems: 20, affection: 30, unlocks: ['Khả năng kể chuyện', 'Quà tulip'] },
  { level: 10, coins: 500, gems: 50, affection: 50, unlocks: ['Gợi ý hoạt động', 'Vòng tay bạc', 'Scene: Công viên'] },
  { level: 15, coins: 800, gems: 80, affection: 80, unlocks: ['Viết thơ ngẫu hứng', 'Dây chuyền vàng'] },
  { level: 20, coins: 1000, gems: 100, affection: 100, unlocks: ['Chia sẻ bí mật', 'Chuyến du lịch'] },
  { level: 25, coins: 1500, gems: 150, affection: 150, unlocks: ['Kỷ niệm đặc biệt', 'Nhẫn kim cương'] },
  { level: 30, coins: 2000, gems: 200, affection: 200, unlocks: ['Tình yêu vĩnh cửu'] },
];

// NEW: XP scaling formula - higher levels need more XP
function getXpRequiredForLevel(level: number): number {
  // Level 1→2: 100 XP
  // Level 5→6: 300 XP
  // Level 10→11: 550 XP
  // Level 20→21: 1050 XP
  // Formula: 100 + (level - 1) * 50
  return 100 + (level - 1) * 50;
}

// NEW: Calculate total XP needed to reach a level from level 1 (O(1) formula)
function getTotalXpForLevel(level: number): number {
  // Arithmetic series: sum(100 + (i-1)*50) for i=1 to level-1
  // = 100*(level-1) + 50*(level-1)*(level-2)/2
  const n = level - 1;
  if (n <= 0) return 0;
  return 100 * n + 25 * n * (n - 1);
}

function calculateRelationshipStage(affection: number): RelationshipStage {
  if (affection >= 900) return 'LOVER';
  if (affection >= 750) return 'DATING';
  if (affection >= 600) return 'CRUSH';
  if (affection >= 450) return 'CLOSE_FRIEND';
  if (affection >= 250) return 'FRIEND';
  if (affection >= 100) return 'ACQUAINTANCE';
  return 'STRANGER';
}

// NEW: Get unlocked features based on level
function getUnlockedFeatures(level: number): string[] {
  const features: string[] = [];
  for (const milestone of LEVEL_MILESTONES) {
    if (level >= milestone.level) {
      features.push(...milestone.unlocks);
    }
  }
  return features;
}

export const characterService = {
  async getActiveCharacter(userId: string) {
    // Try cache first
    const cacheKey = CacheKeys.character(userId);
    const cached = await cache.get<any>(cacheKey);
    if (cached) return cached;

    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
      include: {
        template: true,
        characterFacts: {
          orderBy: { importance: 'desc' },
          take: 20,
        },
        scenes: {
          include: { scene: true },
        },
      },
    });

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER');
    }

    // Add unlocked features to response
    const unlockedFeatures = getUnlockedFeatures(character.level);
    const xpForNextLevel = getXpRequiredForLevel(character.level);
    const progressPercent = Math.round((character.experience / xpForNextLevel) * 100);

    const result = {
      ...character,
      unlockedFeatures,
      xpForNextLevel,
      progressPercent,
    };

    // Cache result
    await cache.set(cacheKey, result, CacheTTL.CHARACTER);

    return result;
  },

  async createCharacter(userId: string, data: CreateCharacterData) {
    log.debug('Creating character with data:', {
      userId,
      name: data.name,
      age: data.age,
      occupation: data.occupation,
      personality: data.personality,
    });

    // Use transaction to ensure atomicity: deactivate old characters and create new one
    const character = await prisma.$transaction(async (tx) => {
      // Deactivate other characters
      await tx.character.updateMany({
        where: { userId },
        data: { isActive: false },
      });

      // Create new character
      return tx.character.create({
        data: {
          userId,
          name: data.name,
          nickname: data.nickname,
          gender: data.gender || 'FEMALE',
          personality: data.personality || 'caring',
          birthday: data.birthday ? new Date(data.birthday) : undefined,
          bio: data.bio || `Xin chao! Toi la ${data.name}`,
          age: data.age || 22,
          occupation: data.occupation || 'student',
          templateId: data.templateId || undefined,
          avatarUrl: data.avatarUrl || undefined,
          isActive: true,
        },
        include: {
          template: true,
        },
      });
    });

    log.debug('Character created:', {
      id: character.id,
      name: character.name,
      age: character.age,
      occupation: character.occupation,
    });

    // Invalidate caches for this user
    await cache.del(CacheKeys.character(userId));
    await cache.del(CacheKeys.characterWithFacts(character.id));
    await cache.del(`user:${userId}:characters:list`);

    return character;
  },

  async updateCharacter(userId: string, data: UpdateCharacterData) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
    });

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER');
    }

    const updated = await prisma.character.update({
      where: { id: character.id },
      data,
    });

    // Invalidate caches
    await cache.del(CacheKeys.character(userId));
    await cache.del(CacheKeys.characterWithFacts(character.id));

    return updated;
  },

  async customizeCharacter(userId: string, data: CustomizeCharacterData) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
    });

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER');
    }

    const updated = await prisma.character.update({
      where: { id: character.id },
      data,
    });

    // Invalidate caches
    await cache.del(CacheKeys.character(userId));
    await cache.del(CacheKeys.characterWithFacts(character.id));

    return updated;
  },

  async getFacts(userId: string) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
    });

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER');
    }

    return prisma.characterFact.findMany({
      where: { characterId: character.id },
      orderBy: [{ importance: 'desc' }, { createdAt: 'desc' }],
    });
  },

  async addFact(userId: string, data: AddFactData) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
    });

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER');
    }

    const fact = await prisma.characterFact.upsert({
      where: {
        characterId_key: {
          characterId: character.id,
          key: data.key,
        },
      },
      update: {
        value: data.value,
        category: data.category,
        importance: data.importance || 5,
      },
      create: {
        characterId: character.id,
        category: data.category,
        key: data.key,
        value: data.value,
        importance: data.importance || 5,
      },
    });

    // Invalidate character cache after adding/updating fact
    await cache.del(CacheKeys.characterWithFacts(character.id));

    return fact;
  },

  async getRelationshipStatus(userId: string) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
    });

    if (!character) {
      throw new AppError('No active character found', 404, 'NO_CHARACTER');
    }

    const currentStage = character.relationshipStage;
    const nextStage = Object.entries(RELATIONSHIP_THRESHOLDS).find(
      ([_, threshold]) => threshold > character.affection
    );

    // NEW: Enhanced relationship status with level info
    const xpForNextLevel = getXpRequiredForLevel(character.level);
    const unlockedFeatures = getUnlockedFeatures(character.level);
    const nextMilestone = LEVEL_MILESTONES.find(m => m.level > character.level);

    return {
      currentStage,
      affection: character.affection,
      level: character.level,
      experience: character.experience,
      xpForNextLevel,
      progressToNextLevel: Math.round((character.experience / xpForNextLevel) * 100),
      nextStage: nextStage ? nextStage[0] : null,
      nextStageThreshold: nextStage ? nextStage[1] : null,
      progressToNextStage: nextStage
        ? Math.round(
          ((character.affection - RELATIONSHIP_THRESHOLDS[currentStage]) /
            (nextStage[1] - RELATIONSHIP_THRESHOLDS[currentStage])) *
          100
        )
        : 100,
      unlockedFeatures,
      nextMilestone: nextMilestone ? {
        level: nextMilestone.level,
        unlocks: nextMilestone.unlocks,
      } : null,
    };
  },

  async updateAffection(characterId: string, amount: number, userId?: string) {
    const character = await prisma.character.findUnique({
      where: { id: characterId },
      select: { id: true, userId: true, affection: true, relationshipStage: true },
    });

    if (!character) {
      throw new AppError('Character not found', 404, 'CHARACTER_NOT_FOUND');
    }

    // Authorization check: if userId is provided, verify ownership
    if (userId && character.userId !== userId) {
      throw new AppError('Not authorized to update this character', 403, 'FORBIDDEN');
    }

    const newAffection = Math.max(
      VALIDATION.AFFECTION_MIN,
      Math.min(VALIDATION.AFFECTION_MAX, character.affection + amount)
    );
    const newStage = calculateRelationshipStage(newAffection);
    const stageChanged = newStage !== character.relationshipStage;

    const updated = await prisma.character.update({
      where: { id: characterId },
      data: {
        affection: newAffection,
        relationshipStage: newStage,
      },
    });

    // Invalidate character cache
    await cache.del(CacheKeys.character(character.userId), CacheKeys.characterById(characterId));

    return {
      ...updated,
      stageChanged,
      previousStage: character.relationshipStage,
    };
  },

  // Enhanced addExperience with XP scaling and level-up rewards
  async addExperience(characterId: string, xp: number): Promise<{
    character: any;
    leveledUp: boolean;
    previousLevel: number;
    newLevel: number;
    milestoneReward: LevelMilestoneReward | null;
  }> {
    const character = await prisma.character.findUnique({
      where: { id: characterId },
    });

    if (!character) {
      throw new AppError('Character not found', 404, 'CHARACTER_NOT_FOUND');
    }

    const previousLevel = character.level;
    let newXp = character.experience + xp;
    let newLevel = character.level;
    let milestoneReward: LevelMilestoneReward | null = null;

    // Check for level ups with scaling XP
    let xpNeeded = getXpRequiredForLevel(newLevel);
    while (newXp >= xpNeeded) {
      newXp -= xpNeeded;
      newLevel++;
      xpNeeded = getXpRequiredForLevel(newLevel);

      // Check if this level is a milestone
      const milestone = LEVEL_MILESTONES.find(m => m.level === newLevel);
      if (milestone) {
        milestoneReward = milestone;
      }
    }

    // Update character
    const updatedCharacter = await prisma.character.update({
      where: { id: characterId },
      data: {
        experience: newXp,
        level: newLevel,
      },
    });

    // If leveled up and hit a milestone, give rewards
    if (milestoneReward && character.userId) {
      await prisma.user.update({
        where: { id: character.userId },
        data: {
          coins: { increment: milestoneReward.coins },
          gems: { increment: milestoneReward.gems },
        },
      });

      // Add milestone affection
      if (milestoneReward.affection > 0) {
        await prisma.character.update({
          where: { id: characterId },
          data: {
            affection: { increment: milestoneReward.affection },
          },
        });
      }

      // Create memory for milestone
      await prisma.memory.create({
        data: {
          userId: character.userId,
          characterId,
          type: 'MILESTONE',
          title: `Đạt Level ${milestoneReward.level}! 🎉`,
          description: `Bạn đã đạt level ${milestoneReward.level} với ${character.name}. Mở khóa: ${milestoneReward.unlocks.join(', ')}`,
          milestone: `LEVEL_${milestoneReward.level}`,
          metadata: {
            level: milestoneReward.level,
            coins: milestoneReward.coins,
            gems: milestoneReward.gems,
            affection: milestoneReward.affection,
            unlocks: milestoneReward.unlocks,
          },
        },
      });
    }

    // Invalidate character cache
    await cache.del(CacheKeys.character(character.userId), CacheKeys.characterById(characterId));

    return {
      character: updatedCharacter,
      leveledUp: newLevel > previousLevel,
      previousLevel,
      newLevel,
      milestoneReward,
    };
  },

  // NEW: Get XP info for display
  getXpInfo(level: number, experience: number) {
    const xpForNextLevel = getXpRequiredForLevel(level);
    const totalXpForCurrentLevel = getTotalXpForLevel(level);
    const totalXpForNextLevel = getTotalXpForLevel(level + 1);

    return {
      currentXp: experience,
      xpForNextLevel,
      totalXpForCurrentLevel,
      totalXpForNextLevel,
      progressPercent: Math.round((experience / xpForNextLevel) * 100),
    };
  },

  // NEW: Get level milestone info
  getLevelMilestones() {
    return LEVEL_MILESTONES;
  },

  // NEW: Check what features are unlocked at current level
  async getUnlockedFeaturesForUser(userId: string) {
    const character = await prisma.character.findFirst({
      where: { userId, isActive: true },
    });

    if (!character) {
      return { features: [], nextUnlock: LEVEL_MILESTONES[0] };
    }

    const features = getUnlockedFeatures(character.level);
    const nextMilestone = LEVEL_MILESTONES.find(m => m.level > character.level);

    return {
      features,
      currentLevel: character.level,
      nextUnlock: nextMilestone || null,
      levelsToNextUnlock: nextMilestone ? nextMilestone.level - character.level : 0,
    };
  },
};

import { Request, Response, NextFunction } from 'express';
import { prisma, PremiumTier } from '../lib/prisma';
import { AppError } from './error.middleware';
import { isVipTier } from '../lib/constants';
import { getTierConfig, TierConfig } from '../modules/admin/tier-config.service';
import { logger } from '../lib/logger';

// Premium tier hierarchy (higher index = more features)
const TIER_HIERARCHY: PremiumTier[] = ['FREE', 'BASIC', 'PRO', 'ULTIMATE'];

/**
 * Check if premium subscription has expired
 * Returns true if expired (should downgrade to FREE)
 */
function isPremiumExpired(expiresAt: Date | null): boolean {
  if (!expiresAt) return false; // No expiration = lifetime
  return new Date() > expiresAt;
}

/**
 * Auto-downgrade user to FREE tier if premium expired
 * Called silently during request processing
 */
async function autoDowngradeIfExpired(userId: string, expiresAt: Date | null): Promise<boolean> {
  if (!isPremiumExpired(expiresAt)) return false;

  try {
    await prisma.user.update({
      where: { id: userId },
      data: {
        isPremium: false,
        premiumTier: 'FREE',
        // Keep premiumExpiresAt for record
      },
    });
    logger.info(`User ${userId} premium expired - auto-downgraded to FREE`);
    return true;
  } catch (error) {
    logger.error(`Failed to auto-downgrade user ${userId}:`, error);
    return false;
  }
}

/**
 * Check if user has premium subscription (any paid tier)
 */
export function requirePremium(req: Request, res: Response, next: NextFunction) {
  const user = req.user;

  if (!user) {
    return next(new AppError('Authentication required', 401, 'UNAUTHORIZED'));
  }

  // Check isPremium flag or premiumTier
  if (user.isPremium || (user.premiumTier && user.premiumTier !== 'FREE')) {
    return next();
  }

  return next(new AppError('Premium subscription required', 403, 'PREMIUM_REQUIRED'));
}

/**
 * Require specific premium tier or higher
 */
export function requireTier(minTier: PremiumTier) {
  return async (req: Request, res: Response, next: NextFunction) => {
    const userId = req.user?.id;

    if (!userId) {
      return next(new AppError('Authentication required', 401, 'UNAUTHORIZED'));
    }

    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { premiumTier: true, isPremium: true, premiumExpiresAt: true },
    });

    if (!user) {
      return next(new AppError('User not found', 404, 'USER_NOT_FOUND'));
    }

    const userTier = user.premiumTier || 'FREE';
    const userTierIndex = TIER_HIERARCHY.indexOf(userTier);
    const requiredTierIndex = TIER_HIERARCHY.indexOf(minTier);

    if (userTierIndex >= requiredTierIndex) {
      return next();
    }

    // Check if premium has expired
    if (user.premiumExpiresAt && new Date() > user.premiumExpiresAt) {
      return next(new AppError(`Your premium subscription has expired. ${minTier} tier required.`, 403, 'PREMIUM_EXPIRED'));
    }

    return next(new AppError(`${minTier} subscription tier required`, 403, 'TIER_REQUIRED'));
  };
}

/**
 * Check feature access based on dynamic tier config
 */
export function requireFeature(feature: keyof TierConfig) {
  return async (req: Request, res: Response, next: NextFunction) => {
    const userId = req.user?.id;

    if (!userId) {
      return next(new AppError('Authentication required', 401, 'UNAUTHORIZED'));
    }

    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { premiumTier: true, isPremium: true },
    });

    if (!user) {
      return next(new AppError('User not found', 404, 'USER_NOT_FOUND'));
    }

    const tier = (user.premiumTier || 'FREE') as PremiumTier;
    const config = await getTierConfig(tier);
    const value = config[feature];

    if (typeof value === 'boolean' && !value) {
      return next(new AppError(`Feature "${feature}" requires a premium subscription`, 403, 'FEATURE_LOCKED'));
    }
    if (typeof value === 'number' && value === 0) {
      return next(new AppError(`Feature "${feature}" requires a premium subscription`, 403, 'FEATURE_LOCKED'));
    }

    return next();
  };
}

/**
 * Add user premium info to request for conditional logic in handlers
 * Also auto-downgrades expired premium users to FREE tier
 */
export async function attachPremiumInfo(req: Request, res: Response, next: NextFunction) {
  const userId = req.user?.id;

  if (!userId) {
    return next();
  }

  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: {
      premiumTier: true,
      isPremium: true,
      premiumExpiresAt: true,
    },
  });

  if (user) {
    // Check and auto-downgrade if expired
    const expired = await autoDowngradeIfExpired(userId, user.premiumExpiresAt);

    // Use downgraded values if expired
    const tier = (expired ? 'FREE' : (user.premiumTier || 'FREE')) as PremiumTier;
    const isPremium = expired ? false : (user.isPremium || tier !== 'FREE');
    const features = await getTierConfig(tier);

    req.premiumInfo = {
      tier,
      isPremium,
      isVip: isVipTier(tier),
      features,
      expiresAt: user.premiumExpiresAt,
      expired,
    };
  }

  next();
}

// Extend Express Request type for premium info
declare global {
  namespace Express {
    interface Request {
      premiumInfo?: {
        tier: PremiumTier;
        isPremium: boolean;
        isVip: boolean;
        features: TierConfig;
        expiresAt: Date | null;
        expired: boolean;
      };
    }
  }
}

