          // Token was cleared (logout from another tab)
          useAuthStore.setState({
            accessToken: null,
            user: null,
            isAuthenticated: false,
          });
          useChatStore.getState().clearMessages();
          useCharacterStore.getState().clear();
        }
      } catch {
        // Ignore parse errors
      }
    }
  });
