          characterId: data.characterId,
          role: 'SYSTEM',
          content: `Bạn đã tặng ${gift.name}`,
          messageType: 'GIFT',
          metadata: { giftId: data.giftId, giftName: gift.name },
        },
      });

      await tx.message.create({
        data: {
          userId,
          characterId: data.characterId,
          role: 'AI',
          content: reaction,
          messageType: 'TEXT',
          emotion: 'love',
        },
      });

      return { success: true, gift };
    });

